  'chapters.title': { en: 'Book Roadmap', ka: 'წიგნის გზამკვლევი', ru: 'Путеводитель по книге', hy: 'Գրքի ճանապարհային քարտեզ' },
  'chapters.subtitle': { en: 'Follow the chapters of "Psychology and Life" — your study guide from start to finish', ka: 'მიჰყევით წიგნს "ფსიქოლოგია და ცხოვრება" — თქვენი მეგზური სწავლის პროცესში', ru: 'Следуйте по главам книги «Психология и жизнь» — вашего путеводителя в обучении', hy: 'Հետևեք «Հոգեբանություն և կյանք» գրքի գլուխներին. ձեր ուսումնական ուղեցույցը սկզբից մինչև վերջ' },
  'chapters.chapter': { en: 'Chapter', ka: 'თავი', ru: 'Глава', hy: 'Գլուխ' },
